translated_files.mix_kernels.cl:
#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 ENABLE
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 ENABLE
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 1
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef BLOCK_STRIDED
#define STRIDE blockdim
#else
#define STRIDE 1
#endif

#ifdef ENABLE_HP
typedef short cl_half2[2];
#endif

__attribute__((reqd_work_group_size(blockdim)))
void benchmark_func(class_T seed, class_T* data) {
    size_t gid = get_global_id(0);
    size_t local_id = get_local_id(0);

    class_T sum = (class_T)0;

    for (unsigned int fusion_idx = 0; fusion_idx < FUSION_DEGREE; fusion_idx++) {
        for (unsigned int elem_idx = 0; elem_idx < ELEMENTS_PER_THREAD; elem_idx++) {
#ifdef BLOCK_STRIDED
            size_t idx = gid * ELEMENTS_PER_THREAD * FUSION_DEGREE + 
                         local_id * STRIDE * ELEMENTS_PER_THREAD * FUSION_DEGREE +
                         elem_idx * FUSION_DEGREE + fusion_idx;
#else
            size_t idx = gid * ELEMENTS_PER_THREAD * FUSION_DEGREE + 
                         elem_idx * FUSION_DEGREE + fusion_idx;
#endif

            class_T t = data[idx];
            class_T f = seed;

            for (unsigned int iter = 0; iter < COMPUTE_ITERATIONS; iter++) {
                t = t * t + f;
            }

            sum += t;
        }
    }

    if (elem_idx == 0 && fusion_idx == 0) {
        data[gid] = sum;
    }
}

#ifdef BLOCK_STRIDED
__attribute__((reqd_work_group_size(blockdim)))
void benchmark_func_warmup(short seed, class_T* data) {
    size_t gid = get_global_id(0);
    size_t local_id = get_local_id(0);

    for (unsigned int i = 0; i < ELEMENTS_PER_THREAD * FUSION_DEGREE; i++) {
        size_t idx = gid * ELEMENTS_PER_THREAD * FUSION_DEGREE + 
                     local_id * STRIDE * ELEMENTS_PER_THREAD * FUSION_DEGREE + i;
        data[idx] = (class_T)0;
    }
}
#else
__attribute__((reqd_work_group_size(blockdim)))
void benchmark_func_warmup(short seed, class_T* data) {
    size_t gid = get_global_id(0);

    for (unsigned int i = 0; i < ELEMENTS_PER_THREAD * FUSION_DEGREE; i++) {
        size_t idx = gid * ELEMENTS_PER_THREAD * FUSION_DEGREE + i;
        data[idx] = (class_T)0;
    }
}
#endif
